     import { getTopicRules } from "./topic-rules.js";

     function detectTopics(text: string): string[] {
       const lower = text.toLowerCase();
       const matched: string[] = [];
       for (const rule of getTopicRules()) {
         const nameWords = rule.topic.split("-").filter((w) => w.length >= 2);
         const needles = [...nameWords, ...rule.keywords];
         if (needles.some((kw) => kw.length >= 2 && lower.includes(kw.toLowerCase()))) {
